1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells each with one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block of 2x2 cells unchanged (still life, survival)", () => {
15	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const expected: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
17	    const result = nextGeneration(input);
18	    expect(result).toHaveLength(expected.length);
19	    expect(result).toEqual(expect.arrayContaining(expected));
20	  });
21	  it("should transform a vertical blinker into a horizontal blinker (survival and reproduction)", () => {
22	    const input: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
23	    const expected: Array<[number, number]> = [[-1, 1], [0, 1], [1, 1]];
24	    const result = nextGeneration(input);
25	    expect(result).toHaveLength(expected.length);
26	    expect(result).toEqual(expect.arrayContaining(expected));
27	  });
28	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
29	    const input: Array<[number, number]> = [
30	      [0, 0], [1, 0], [2, 0],
31	      [1, 1],
32	      [0, 2], [1, 2], [2, 2],
33	    ];
34	    const result = nextGeneration(input);
35	    expect(result).not.toContainEqual([1, 1]);
36	  });
37	  it("should bring a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
38	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
39	    const result = nextGeneration(input);
40	    expect(result).toContainEqual([1, 1]);
41	  });
42	  it.todo("should handle negative coordinates");
43	});
