1	type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const parseCellKey = (key: string): Cell => {
6	  const [xStr, yStr] = key.split(",");
7	  return [Number(xStr), Number(yStr)];
8	};
9	
10	const neighborOffsets: ReadonlyArray<Cell> = [
11	  [-1, -1], [-1, 0], [-1, 1],
12	  [ 0, -1],          [ 0, 1],
13	  [ 1, -1], [ 1, 0], [ 1, 1],
14	];
15	
16	const neighborsOf = (x: number, y: number): Cell[] =>
17	  neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]);
18	
19	const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number =>
20	  neighborsOf(x, y).filter(([nx, ny]) => liveSet.has(cellKey(nx, ny))).length;
21	
22	const willBeAlive = (isCurrentlyAlive: boolean, liveNeighbors: number): boolean =>
23	  isCurrentlyAlive ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;
24	
25	const candidateCellsFor = (liveCells: Array<Cell>): Set<string> => {
26	  const candidates = new Set<string>();
27	  for (const [x, y] of liveCells) {
28	    candidates.add(cellKey(x, y));
29	    for (const [nx, ny] of neighborsOf(x, y)) {
30	      candidates.add(cellKey(nx, ny));
31	    }
32	  }
33	  return candidates;
34	};
35	
36	export const nextGeneration = (liveCells: Array<Cell>): Array<Cell> => {
37	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
38	  const candidates = candidateCellsFor(liveCells);
39	
40	  return Array.from(candidates)
41	    .map(parseCellKey)
42	    .filter(([x, y]) => willBeAlive(liveSet.has(cellKey(x, y)), countLiveNeighbors(x, y, liveSet)));
43	};
